        expected_y[49][8] = 64'h78927f80d1173590;
        expected_y[49][9] = 64'h15e01bc523808822;
        salt[49][0] = 64'hd9d63b25c7d3bffa;
        salt[49][1] = 64'h9cf0d1a66c825cfd;
        salt[49][2] = 64'h9f0165b8ad10f458;
