        expected_hash_mpc[49][6] = 64'hd4518d20b75a33d2;
        expected_hash_mpc[49][7] = 64'h1f73712bb184ff22;
        expected_ctr[49] = 64'h000000000000005c;

    if (!$value$plusargs("NUM_RUNS=%d", num_runs)) begin
        num_runs = NUM_VECTORS;
    end
    if (num_runs <= 0 || num_runs > NUM_VECTORS) begin
        $fatal(1, "NUM_RUNS must be in the range 1..%0d", NUM_VECTORS);
    end

    sign_cycles = new[num_runs];
    verify_cycles = new[num_runs];

    @(posedge tb_clk);
    for (run_idx = 0; run_idx < num_runs; run_idx = run_idx + 1) begin
        #(2.1 * CLK_PERIOD);
        tb_rst = 1'b1;
        #(2 * CLK_PERIOD);
        program_sign_inputs(run_idx);
        tb_rst = 1'b0;

        wait (tb_done === 1'b0);
        tb_start = `START_SIGN;
        sign_start_time = $time;
        #(CLK_PERIOD);
        tb_start = '0;

        wait (tb_done === 1'b1);
        sign_done_time = $time;
        sign_cycles[run_idx]
            = (sign_done_time - sign_start_time) / CLK_PERIOD;
        sign_sum_cycles = sign_sum_cycles + sign_cycles[run_idx];
        #1;
        check_sign_outputs(run_idx);
        $display("Run %0d/%0d SIGN correct: %0d cycles",
                 run_idx + 1, num_runs, sign_cycles[run_idx]);

        #(10 * CLK_PERIOD);
        tb_rst = 1'b1;
        #(2 * CLK_PERIOD);
        tb_rst = 1'b0;

        wait (tb_done === 1'b0);
        tb_start = `START_VERIFY;
        verify_start_time = $time;
        #(CLK_PERIOD);
        tb_start = '0;

        wait (tb_done === 1'b1);
        verify_done_time = $time;
        verify_cycles[run_idx]
            = (verify_done_time - verify_start_time) / CLK_PERIOD;
        verify_sum_cycles = verify_sum_cycles + verify_cycles[run_idx];
        #1;
        if (tb_bad_sig !== 1'b0) begin
            $fatal(1, "Run %0d VERIFY failed: bad_sig=%b",
                   run_idx, tb_bad_sig);
        end
        $display("Run %0d/%0d VERIFY correct: %0d cycles",
                 run_idx + 1, num_runs, verify_cycles[run_idx]);
        #(10 * CLK_PERIOD);
    end

    sign_average_cycles = real'(sign_sum_cycles) / real'(num_runs);
    verify_average_cycles = real'(verify_sum_cycles) / real'(num_runs);
    sign_cycles.sort();
    verify_cycles.sort();
    if (num_runs % 2) begin
        sign_median_cycles = real'(sign_cycles[num_runs / 2]);
        verify_median_cycles = real'(verify_cycles[num_runs / 2]);
    end else begin
        sign_median_cycles
            = (real'(sign_cycles[num_runs / 2 - 1])
               + real'(sign_cycles[num_runs / 2])) / 2.0;
        verify_median_cycles
            = (real'(verify_cycles[num_runs / 2 - 1])
               + real'(verify_cycles[num_runs / 2])) / 2.0;
    end

    $display("==== LATENCY over %0d sign/verify pairs ====", num_runs);
    $display("AVERAGE SIGN   = %.3f cycles", sign_average_cycles);
    $display("MEDIAN  SIGN   = %.3f cycles", sign_median_cycles);
    $display("AVERAGE VERIFY = %.3f cycles", verify_average_cycles);
    $display("MEDIAN  VERIFY = %.3f cycles", verify_median_cycles);
    $display("All %0d deterministic sign/verify pairs correct", num_runs);
    $finish;
end

endmodule

